const payload = $json;
const message = payload.message || {};
const chat = payload.chat || {};

const text = String(message.text || '').trim();
const hasMedia = Boolean(message.has_media);
if (!text && !hasMedia) {
  return [];
}

const source_channel_id = String(chat.id ?? '');
const source_message_id = String(message.id ?? '');
const source_content_hash = `${source_channel_id}:${source_message_id}:${text.slice(0,120)}`;

return [{
  ...payload,
  normalized: {
    source_type: 'telegram',
    source_channel_id,
    source_channel_name: chat.title || chat.username || null,
    source_message_id,
    source_timestamp: message.date_utc || null,
    source_content_type: hasMedia ? (message.media_type === 'photo' ? 'image' : 'mixed') : 'text',
    source_raw_text: text,
    source_raw_payload: payload,
    source_content_hash
  }
}];

